import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AdminDashboard() {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passInput, setPassInput] = useState("");

  // 1. Admin Security Check
  const handleAdminLogin = (e) => {
    e.preventDefault();
    if (passInput === "admin123") {
      setIsAuthenticated(true);
      fetchRequests();
    } else {
      alert("❌ Incorrect Admin Password!");
    }
  };

  const fetchRequests = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
      setLoading(false);
    } catch (err) { console.error(err); setLoading(false); }
  };

  const handleUpdate = async (id, updatedData) => {
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, updatedData);
      fetchRequests(); 
    } catch (err) { alert("Error updating!"); }
  };

  // --- Login Screen UI ---
  if (!isAuthenticated) {
    return (
      <div className="admin-login-container d-flex align-items-center justify-content-center min-vh-100 bg-light">
        <div className="card shadow-lg p-4 border-0 rounded-4" style={{ width: '350px' }}>
          <div className="text-center mb-4">
            <div className="admin-icon bg-primary text-white rounded-circle d-inline-flex align-items-center justify-content-center mb-2" style={{width:'60px', height:'60px'}}>
              <i className="fas fa-user-shield fa-2x"></i>
            </div>
            <h4 className="fw-bold">Admin Portal</h4>
            <p className="text-muted small">Enter password to access control panel</p>
          </div>
          <form onSubmit={handleAdminLogin}>
            <input 
              type="password" 
              className="form-control mb-3 py-2 text-center" 
              placeholder="••••••••" 
              onChange={(e) => setPassInput(e.target.value)}
              required 
            />
            <button className="btn btn-primary w-100 fw-bold py-2">Unlock Dashboard</button>
          </form>
        </div>
      </div>
    );
  }

  if (loading) return <div className="text-center py-5">Loading Admin Panel...</div>;

  return (
    <div className="admin-page bg-light min-vh-100 pb-5">
      {/* Navbar Style Header */}
      <div className="bg-dark text-white py-4 mb-5 shadow">
        <div className="container d-flex justify-content-between align-items-center">
          <h2 className="fw-bold mb-0">Admin <span className="text-primary">Control Panel</span></h2>
          <button className="btn btn-outline-light btn-sm fw-bold" onClick={() => setIsAuthenticated(false)}>Logout</button>
        </div>
      </div>

      <div className="container">
        <div className="row g-4">
          {requests.map((project) => {
            const remaining = project.totalBudget - project.advancePaid;

            return (
              <div key={project._id} className="col-12">
                <div className="card shadow-sm border-0 rounded-4 p-4 admin-card">
                  <div className="row align-items-center">
                    
                    {/* 1. Client Info */}
                    <div className="col-md-3 border-end-md">
                      <h5 className="fw-bold mb-0 text-capitalize">{project.fullName}</h5>
                      <small className="text-primary fw-bold text-uppercase">{project.serviceType}</small>
                      <p className="small text-muted mb-0 mt-1"><i className="fas fa-envelope me-1"></i>{project.email}</p>
                    </div>

                    {/* 2. Progress Slider */}
                    <div className="col-md-3 px-md-4 py-3 py-md-0">
                      <div className="d-flex justify-content-between mb-2">
                        <small className="fw-bold text-muted">Project Progress</small>
                        <small className="fw-bold text-primary">{project.progress}%</small>
                      </div>
                      <div className="progress rounded-pill mb-2" style={{height:'8px'}}>
                        <div className="progress-bar bg-primary" style={{width: `${project.progress}%`}}></div>
                      </div>
                      <input 
                        type="range" className="form-range custom-range" min="0" max="100" 
                        value={project.progress} 
                        onChange={(e) => handleUpdate(project._id, { progress: e.target.value })}
                      />
                    </div>

                    {/* 3. Payment Section */}
                    <div className="col-md-3 text-center border-start-md border-end-md py-2">
                      <small className="text-muted d-block mb-1 text-uppercase fw-bold" style={{fontSize:'10px', letterSpacing:'1px'}}>Remaining Balance</small>
                      <h3 className={`fw-bold mb-2 ${remaining > 0 ? 'text-danger' : 'text-success'}`}>
                        ₹{remaining}
                      </h3>
                      <div className="d-flex justify-content-center gap-2">
                        <button className="btn btn-xs btn-light border py-1 px-2 small-text" onClick={() => {
                          const budget = prompt("Enter Total Budget:", project.totalBudget);
                          if(budget) handleUpdate(project._id, { totalBudget: budget });
                        }}>Set Budget</button>
                        <button className="btn btn-xs btn-light border py-1 px-2 small-text" onClick={() => {
                          const paid = prompt("Enter Amount Paid:", project.advancePaid);
                          if(paid) handleUpdate(project._id, { advancePaid: paid, paymentStatus: Number(paid) >= project.totalBudget ? 'Paid' : 'Unpaid' });
                        }}>Update Paid</button>
                      </div>
                    </div>

                    {/* 4. Final Actions */}
                    <div className="col-md-3 text-end">
                      {project.paymentStatus === 'Paid' ? (
                        <span className="badge bg-success-light text-success p-2 px-3 rounded-pill fw-bold">✅ Fully Paid</span>
                      ) : (
                        <button 
                          className="btn btn-outline-success btn-sm fw-bold px-3 rounded-pill"
                          onClick={() => handleUpdate(project._id, { advancePaid: project.totalBudget, paymentStatus: 'Paid' })}
                        >Mark Full Paid</button>
                      )}
                      <button className="btn btn-link text-danger ms-2 p-0" onClick={() => {if(window.confirm("Delete request?")) axios.delete(`http://localhost:5000/api/delete-request/${project._id}`).then(fetchRequests)}}>
                        <i className="fas fa-trash-alt"></i>
                      </button>
                    </div>

                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* --- INTERNAL CSS --- */}
      <style>{`
        .admin-card { transition: transform 0.2s ease; border: 1px solid #eee; }
        .admin-card:hover { transform: translateY(-3px); box-shadow: 0 10px 20px rgba(0,0,0,0.05) !important; }
        .bg-success-light { background-color: #e8f5e9; }
        .small-text { font-size: 11px; font-weight: bold; }
        .custom-range::-webkit-slider-thumb { background: #0d6efd; }
        @media (min-width: 768px) {
          .border-end-md { border-right: 1px solid #eee; }
          .border-start-md { border-left: 1px solid #eee; }
        }
      `}</style>
    </div>
  );
}

export default AdminDashboard;
